+fn build_repo_sync_idempotency_key(worker_id: &WorkerId, sync_roots: &[PathBuf]) -> String {
+    build_repo_sync_idempotency_key_for_command(
+        worker_id,
+        sync_roots,
+        RepoUpdaterAdapterCommand::SyncApply,
+    )
+}
