+        "gh_cli" | "gh" => Some(RepoUpdaterCredentialSource::GhCli),
+        "token_env" | "token" => Some(RepoUpdaterCredentialSource::TokenEnv),
+        "ssh_agent" | "ssh" => Some(RepoUpdaterCredentialSource::SshAgent),
+        _ => None,
+    }
+}
