+
+    RepoUpdaterAuthContext {
+        source,
+        credential_id,
+        issued_at_unix_ms,
+        expires_at_unix_ms,
+        granted_scopes,
+        revoked: false,
+        verified_hosts: Vec::new(),
+    }
